$:/plugins/stobot/bullets/stylesheet.text:
ul { 
  margin-top: 0;
  margin-bottom: 0;
}

ol {
  margin-top: 0;
  margin-bottom: 0;
  list-style-type: decimal;
}

ol ol {
  list-style-type: lower-alpha;
}

ol ol ol {
  list-style-type: lower-roman;
}

ol ol ol ol {
  list-style-type: decimal;
}

ol ol ol ol ol {
  list-style-type: lower-alpha;
}

ol ol ol ol ol ol {
  list-style-type: lower-roman;
}

.bullets-viewer {
  {{$:/plugins/stobot/bullets/settings##css-viewer}}
}

.bullets-viewer li {
  {{$:/plugins/stobot/bullets/settings##css-listitem}} 
}

input.bullets-editbox {
  width: 100%;
  border: 1px solid darkgray;
}

.bullets-editor {
  width: 100%;
  border: 1px solid gray;
  vertical-align: middle;
  padding-top: 1px;
  padding-bottom: 1px;
}

.bullets-viewer .tc-editor-toolbar {
  display: none;
}

iframe.bullets-editor {
  height: calc(1em + 8px);
}

.bullets-linkfix {
  color: red;
}

.tc-editor-toolbar {
  margin-top: 0px;
}

[data-tags*="$:/tags/bullets/editing"].tc-tiddler-view-frame .tc-tiddler-controls button:not(.bullets-btn) {
  display: none;
}

.tc-tiddler-view-frame [data-tag-title="$:/tags/bullets/editing"] {
  display: none;
}
